import React from 'react';

/**
 * Logo Component
 * @param {string} size - sm (32px), md (48px), lg (80px), xl (120px)
 * @param {string} variant - 'full' (icon + text), 'icon' (icon only)
 * @param {object} style - extra styles
 */
const Logo = ({ size = 'md', variant = 'full', style = {} }) => {
  const sizes = {
    sm: 32,
    md: 48,
    lg: 80,
    xl: 120
  };

  const currentSize = sizes[size] || sizes.md;
  const imagePath = variant === 'icon' ? '/assets/logo_icon.png' : '/assets/logo.png';

  // Hover effect and transition styles
  const containerStyle = {
    display: 'inline-flex',
    alignItems: 'center',
    justifyContent: variant === 'icon' ? 'center' : 'flex-start',
    transition: 'all 0.3s cubic-bezier(0.16, 1, 0.3, 1)',
    cursor: 'pointer',
    ...style
  };

  const imageStyle = {
    height: `${currentSize}px`,
    width: 'auto',
    objectFit: 'contain',
    display: 'block',
    transition: 'transform 0.4s ease'
  };

  return (
    <div 
      className="logo-container" 
      style={containerStyle}
      onMouseOver={e => {
        const img = e.currentTarget.querySelector('img');
        if (img) img.style.transform = 'scale(1.05)';
      }}
      onMouseOut={e => {
        const img = e.currentTarget.querySelector('img');
        if (img) img.style.transform = 'scale(1)';
      }}
    >
      <img 
        src={imagePath} 
        alt="ParkSense" 
        style={imageStyle} 
        onError={(e) => {
          // Fallback to FontAwesome icon if image is missing
          e.target.style.display = 'none';
          e.target.nextSibling.style.display = 'flex';
        }}
      />
      <div style={{ display: 'none', alignItems: 'center', gap: '8px' }}>
          <i className="fa-solid fa-square-parking" style={{ fontSize: `${currentSize * 0.8}px`, color: 'var(--accent-primary)' }}></i>
          {variant === 'full' && (
            <span style={{ fontSize: `${currentSize * 0.4}px`, fontWeight: '800', color: 'var(--text-primary)', letterSpacing: '-0.5px' }}>
              ParkSense
            </span>
          )}
      </div>
    </div>
  );
};

export default Logo;
